import java.nio.ByteBuffer;
import java.math.BigInteger;

public class Main {
   public static void main(String[] args){
      System.out.println("Testing "+ formatLongOctalOrBinaryBytes(-1234567, new byte[9], 0, 9));
   }
   public static int formatLongOctalOrBinaryBytes(final long value, final byte[] buf, final int offset, final int length) {
       BigInteger bigIntValue = BigInteger.valueOf(value);
       String binVal=bigIntValue.toString(2);
       if (binVal.length() > length - 1 || value < 0 ){
          for (int i = 0;i <binVal.length();i++)
             buf[offset+i]=(byte)(binVal.charAt(i)-'0');
         return binVal.length()-1+offset;
       } else if (value< TarConstants.MAXSIZE && value >=0){
           formatLongOctalBytes(value,buf,offset,length);
       }else if (length<9) {
           formatLongBinary(value, buf, offset, length, value < 0);
       } else{
           formatBigIntegerBinary(bigIntValue,buf,offset,length,(value & 0x80000000L) != 0 );
       }
       return offset+Math.max(binVal.length(),length-1);
   }
     private static int formatLongOctalBytes(long val, byte[] dest, int dOffset, int dLength) {
       long maxAsOctalChar = TarConstants.MAXSIZE;
       boolean negate = false;
       if (val < 0) {
           val *= -1;
           negate = true;
       }
       if (val <= maxAsOctalChar) {
           for (int i = 0; i < dLength; i++) {
               dest[dOffset + i] = (byte) ((negate ? 0xFF : 0x00) | ((val >> ((dLength - i - 1) * 3)) & 0x7));
           }
           return dOffset + dLength;
       }
       throw new IllegalArgumentException("The value " + val + "is too large!");
   }

     private static int formatLongBinary(long val, byte[] buf, int off, int len,boolean negate) {
        long mask = (1L << (len - 1)) - 1;
        for (int idx = 0; idx < len; ++idx, mask>>=1) {
            buf[off + idx] = (byte)((val & mask) == 0 ? '0':'1');
        }
        buf[off + len-1] = (byte)(negate?'1':'0');
        return len + off;
    }

     private static int formatBigIntegerBinary(BigInteger bval, byte[] buf, int off, int len,boolean negate) {
        String strBinVal =bval.toString(2);
        for (int idx = 0; idx <strBinVal.length();idx++)
            buf[off+idx]=(byte)(strBinVal.charAt(idx)=='0'? 0x00:(negate? 0xFF: 0x80));
        return len + off;
    }

}

